<script setup lang="ts">
import{Head,Link}from'@inertiajs/vue3';import{Bookmark,BriefcaseBusiness,CalendarDays,MapPin,Search,Users,X}from'@lucide/vue';import{onMounted,ref,watch}from'vue';import AppShell from '../../Layouts/AppShell.vue';
const items=ref<any[]>([]),sports=ref<any[]>([]),loading=ref(true),selected=ref<any>(),applying=ref(false),cover=ref(''),notice=ref(''),q=ref(''),type=ref(''),sport=ref(''),city=ref(''),remote=ref(false);let timer:ReturnType<typeof setTimeout>;const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'',days=(d:string)=>Math.max(0,Math.ceil((+new Date(d)-Date.now())/86400000)),label=(v:string)=>v.replaceAll('_',' ').replace(/\b\w/g,c=>c.toUpperCase());const api=async(url:string,o:RequestInit={})=>{const r=await fetch(url,{...o,credentials:'same-origin',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf(),'Content-Type':'application/json'}}),p=await r.json();if(!r.ok)throw new Error(p.message??Object.values(p.errors??{}).flat().join(' '));return p.data??p};const load=async()=>{loading.value=true;const p=new URLSearchParams({per_page:'50'});if(q.value)p.set('q',q.value);if(type.value)p.set('type',type.value);if(sport.value)p.set('sport_id',sport.value);if(city.value)p.set('city',city.value);if(remote.value)p.set('remote','1');items.value=await api(`/api/v1/opportunities?${p}`);loading.value=false};const save=async(i:any)=>{await api(`/api/v1/opportunities/${i.id}/save`,{method:i.viewer.saved?'DELETE':'POST'});i.viewer.saved=!i.viewer.saved};const apply=async()=>{applying.value=true;try{await api(`/api/v1/opportunities/${selected.value.id}/apply`,{method:'POST',body:JSON.stringify({cover_letter:cover.value||null})});selected.value.viewer.applied=true;notice.value='Application submitted.'}catch(e:any){notice.value=e.message}finally{applying.value=false}};watch([q,type,sport,city,remote],()=>{clearTimeout(timer);timer=setTimeout(load,300)});onMounted(async()=>{const s=await fetch('/api/v1/sports',{headers:{Accept:'application/json'}});sports.value=(await s.json()).data??[];load()});
</script>
<template><Head title="Opportunities"/><AppShell><main class="opportunities-page"><header class="opp-heading"><div><h1>Sporting opportunities</h1><p>Discover trials, camps, scout days, jobs and sponsorships.</p></div><Link href="/opportunities/create">Post opportunity</Link></header><section class="opp-filters"><div><Search/><input v-model="q" placeholder="Search opportunities..."/></div><select v-model="type"><option value="">All types</option><option v-for="v in ['trial','job','training_camp','sponsorship','scout_day']" :key="v" :value="v">{{label(v)}}</option></select><select v-model="sport"><option value="">All sports</option><option v-for="s in sports" :key="s.id" :value="String(s.id)">{{s.name}}</option></select><input v-model="city" placeholder="City or town"/><label><input v-model="remote" type="checkbox"/>Remote</label></section><div class="opp-summary"><h2>{{loading?'Loading…':`${items.length} open opportunities`}}</h2><Link href="/applications">My applications</Link></div><section v-if="!loading&&items.length" class="opp-grid"><article v-for="i in items" :key="i.id" class="opp-card"><header><span>{{label(i.type)}}</span><button :class="{saved:i.viewer.saved}" @click="save(i)"><Bookmark/></button></header><h3>{{i.title}}</h3><strong>{{i.poster.name}}</strong><div class="opp-meta"><span><BriefcaseBusiness/>{{i.sport?.name||'All sports'}}</span><span><MapPin/>{{i.location.is_remote?'Remote':[i.location.city,i.location.province].filter(Boolean).join(', ')}}</span><span><CalendarDays/>{{days(i.deadline)}} days left</span><span><Users/>{{i.applications_count}} applications</span></div><p>{{i.description}}</p><footer><Link :href="`/opportunities/${i.id}`">View details</Link><Link v-if="!i.viewer.applied" class="apply" :href="`/opportunities/${i.id}`">Apply now</Link><span v-else>Applied</span></footer></article></section></main></AppShell></template>
